const ROAS_MINIMO = 1.5;
const ROAS_META = 3.0;
const GASTO_MINIMO = 30.0;

function calcularMetricas(dados) {
  const investimento = parseFloat(dados.Investimento || 0);
  const cliques = parseInt(dados.Cliques || 0);
  const vendas = parseInt(dados.Vendas || 0);
  const valor_venda = parseFloat(dados.Valor_Venda || 0);
  const receita = vendas * valor_venda;
  const roas = investimento > 0 ? Math.round((receita / investimento) * 100) / 100 : 0;
  const cpc = cliques > 0 ? Math.round((investimento / cliques) * 100) / 100 : 0;
  const taxa_conversao = cliques > 0 ? Math.round((vendas / cliques) * 100 * 100) / 100 : 0;
  const lucro_liquido = Math.round((receita - investimento) * 100) / 100;
  return {
    campanha: dados.Campanha || "N/A",
    data: dados.Data || "N/A",
    investimento, cliques, vendas,
    receita: Math.round(receita * 100) / 100,
    roas, cpc, taxa_conversao, lucro_liquido
  };
}

const resultados = [];

for (const item of $input.all()) {
  const metricas = calcularMetricas(item.json);
  const roas = metricas.roas;
  const investimento = metricas.investimento;
  const lucro = metricas.lucro_liquido;

  let status, emoji, acao;
  if (roas < ROAS_MINIMO && investimento >= GASTO_MINIMO) {
    [status, emoji, acao] = ["Critico", "🔴", "PAUSAR imediatamente"];
  } else if (roas < ROAS_META && investimento >= GASTO_MINIMO) {
    [status, emoji, acao] = ["Atencao", "🟡", "Revisar criativos e segmentacao"];
  } else if (roas >= ROAS_META && lucro > 0) {
    [status, emoji, acao] = ["Escalavel", "🟢", "ESCALAR - aumentar orcamento"];
  } else {
    [status, emoji, acao] = ["Monitorar", "🔵", "Aguardar mais dados"];
  }

  const mensagem = `${emoji} AD-GUARDIAN ALERTA
Campanha: ${metricas.campanha}
Data: ${metricas.data}
Investimento: R$ ${metricas.investimento.toFixed(2)}
Cliques: ${metricas.cliques}
Vendas: ${metricas.vendas}
Receita: R$ ${metricas.receita.toFixed(2)}
ROAS: ${metricas.roas}x
CPC: R$ ${metricas.cpc.toFixed(2)}
Conv. Rate: ${metricas.taxa_conversao}%
Lucro: R$ ${metricas.lucro_liquido.toFixed(2)}
STATUS: ${status}
ACAO: ${acao}`;

  resultados.push({
    json: { status, emoji, acao, mensagem, metricas }
  });
}

return resultados;
